using System;
using System.Collections.Generic;
using System.Xml;

public class ConfigParser
{
    public Dictionary<string, string> ParseConfig(string xmlFile)
    {
        XmlDocument xmlDoc = new XmlDocument();
        try
        {
            xmlDoc.Load(xmlFile);
        }
        catch (XmlException ex)
        {
            throw new Exception("Error parsing XML file: " + ex.Message);
        }

        XmlNamespaceManager nsmgr = new XmlNamespaceManager(xmlDoc.NameTable);

        Dictionary<string, string> configSettings = new Dictionary<string, string>();

        XmlNodeList nodeList = xmlDoc.SelectNodes("//setting", nsmgr);
        foreach (XmlNode node in nodeList)
        {
            if (node.Attributes["name"] != null && node.Attributes["value"] != null)
            {
                configSettings.Add(node.Attributes["name"].Value, node.Attributes["value"].Value);
            }
        }

        return configSettings;
    }
}